#include <stdio.h>
#include <stdint.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        uint64_t N, K;
        scanf("%llu %llu", &N, &K);
        if (K == 0) {
            printf("0 %llu\n", N);
        } else {
            printf("%llu %llu\n", N / K, N % K);
        }
    }
    return 0;
}

